/**
 * Algorithm eligibility + auto-recommendation for HumpDay (JavaScript port).
 *
 * Mirrors humpday/eligibility.py one-for-one so the JS and Python ports
 * give identical algorithm picks for any (n_dim, n_trials, eval_time)
 * triple. The recommendation grid that the lookup consults lives in
 * docs/js/modules/recommendation-grid.js — auto-generated by
 * benchmarks/build_js_grid_asset.py from the canonical
 * benchmarks/recommendation_grid.json.
 *
 * Two filters decide which optimizers can sensibly run a given problem:
 *
 *   1. Dimensional cap — some optimizers are structurally unfit above a
 *      certain n_dim (GridSearch is exponential, BayesianOpt's GP is
 *      cubic-in-observations, UOBYQA needs (n+1)(n+2)/2 interpolation
 *      points, ...).
 *
 *   2. Per-iteration overhead — every optimizer carries its own
 *      bookkeeping cost. A GP fit or eigendecomposition is rounding
 *      error when each objective call costs a second, but it crushes
 *      wall-clock when each call costs a microsecond. Each algorithm is
 *      tagged with an overhead tier and is allowed only when the timed
 *      objective is expensive enough that HumpDay's overhead stays a
 *      small fraction of total time.
 *
 * The recommender (recommend) consults both filters, then picks the
 * Borda-mean-rank winner on the nearest (n_dim, n_trials) cell of the
 * recommendation grid (with median_best as a fallback for legacy grids
 * and a rule-based ranking as a fallback when no grid is present).
 */

// In Node we require() the grid module; in the browser, the grid is a
// <script>-loaded global. Either way, after this block, `Grid` is the
// `RecommendationGrid` JSON object (or null if the grid script wasn't
// loaded).
let Grid = null;
if (typeof module !== "undefined" && module.exports) {
    try {
        Grid = require("./recommendation-grid.js");
    } catch (e) {
        Grid = null;
    }
} else if (typeof globalThis !== "undefined" && globalThis.RecommendationGrid) {
    Grid = globalThis.RecommendationGrid;
}

// -----------------------------------------------------------------------------
// Overhead tiers
// -----------------------------------------------------------------------------
const TIER_TRIVIAL = 0;
const TIER_LIGHT = 1;
const TIER_MEDIUM = 2;
const TIER_HEAVY = 3;
const TIER_VERY_HEAVY = 4;

const TIER = {
    // Tier 0 — pure sampling baselines only.
    RandomSearch: TIER_TRIVIAL,
    GridSearch: TIER_TRIVIAL,
    // Tier 1 — single-trajectory σ-adaptation and componentwise Gaussian
    // samplers, plus the simplex / direction-set / line-search methods.
    HillClimbing: TIER_LIGHT,
    Rechenberg: TIER_LIGHT,
    NelderMead: TIER_LIGHT,
    Powell: TIER_LIGHT,
    DifferentialEvolution: TIER_LIGHT,
    ParticleSwarm: TIER_LIGHT,
    SimulatedAnnealing: TIER_LIGHT,
    GeneticAlgorithm: TIER_LIGHT,
    EvolutionStrategy: TIER_LIGHT,
    FireflyAlgorithm: TIER_LIGHT,
    HarmonySearch: TIER_LIGHT,
    AntColonyOpt: TIER_LIGHT,
    LBFGSB: TIER_LIGHT,
    PatternSearch: TIER_LIGHT,
    CoordinateDescent: TIER_LIGHT,
    // Tier 2 — small linear-algebra updates per iteration.
    PRIMA_BOBYQA: TIER_MEDIUM,
    PRIMA_NEWUOA: TIER_MEDIUM,
    // Tier 3 — full quadratic model or O(n^3) eigendecomposition per gen.
    PRIMA_UOBYQA: TIER_HEAVY,
    CMAEvolutionStrategy: TIER_HEAVY,
    // Tier 4 — O(n_obs^3) GP fit per iter.
    BayesianOpt: TIER_VERY_HEAVY,
};

const MIN_EVAL_TIME_FOR_TIER = {
    [TIER_TRIVIAL]: 0.0,
    [TIER_LIGHT]: 1e-5,
    [TIER_MEDIUM]: 1e-4,
    [TIER_HEAVY]: 1e-3,
    [TIER_VERY_HEAVY]: 1e-2,
};

// -----------------------------------------------------------------------------
// Dimensional caps — algorithms not listed are treated as having no cap.
// -----------------------------------------------------------------------------
const DIM_CAP = {
    GridSearch: 4,
    BayesianOpt: 10,
    PRIMA_UOBYQA: 12,
    NelderMead: 20,
    PRIMA_NEWUOA: 25,
    PRIMA_BOBYQA: 30,
    Powell: 30,
    PatternSearch: 30,
    FireflyAlgorithm: 50,
    AntColonyOpt: 50,
    CMAEvolutionStrategy: 100,
};

function minTrials(name, n_dim) {
    if (name === "PRIMA_UOBYQA") return Math.floor((n_dim + 1) * (n_dim + 2) / 2) + 5;
    if (name === "PRIMA_NEWUOA" || name === "PRIMA_BOBYQA") return 2 * n_dim + 5;
    if (name === "BayesianOpt") return Math.max(30, 5 * n_dim);
    if (name === "CMAEvolutionStrategy") return Math.max(20, 4 * n_dim);
    if (name === "GridSearch") return Math.max(Math.pow(3, n_dim), 8);
    return 10;
}

function passesDim(name, n_dim) {
    const cap = DIM_CAP[name];
    return cap === undefined ? true : n_dim <= cap;
}

function passesTrials(name, n_dim, n_trials) {
    return n_trials >= minTrials(name, n_dim);
}

function passesEvalTime(name, eval_time) {
    const tier = TIER[name] !== undefined ? TIER[name] : TIER_LIGHT;
    return eval_time >= MIN_EVAL_TIME_FOR_TIER[tier];
}

function filterByDim(names, n_dim) {
    return names.filter(n => passesDim(n, n_dim));
}
function filterByTrials(names, n_dim, n_trials) {
    return names.filter(n => passesTrials(n, n_dim, n_trials));
}
function filterByEvalTime(names, eval_time) {
    return names.filter(n => passesEvalTime(n, eval_time));
}

function eligible(names, n_dim, n_trials, eval_time) {
    let out = filterByDim(names, n_dim);
    out = filterByTrials(out, n_dim, n_trials);
    if (eval_time !== undefined && eval_time !== null) {
        out = filterByEvalTime(out, eval_time);
    }
    return out;
}

// -----------------------------------------------------------------------------
// Objective timing
// -----------------------------------------------------------------------------
function timeObjective(f, xSample, nWarmup = 1, nMeasure = 3) {
    for (let i = 0; i < nWarmup; i++) f(xSample);
    const samples = [];
    for (let i = 0; i < nMeasure; i++) {
        const t0 = (typeof performance !== "undefined" && performance.now)
            ? performance.now() / 1000
            : Date.now() / 1000;
        f(xSample);
        const t1 = (typeof performance !== "undefined" && performance.now)
            ? performance.now() / 1000
            : Date.now() / 1000;
        samples.push(t1 - t0);
    }
    samples.sort((a, b) => a - b);
    const median = samples[Math.floor(samples.length / 2)];
    return { eval_time: median, samples, used_for_recommendation: true };
}

// -----------------------------------------------------------------------------
// Rule-based ranking — mirrors humpday.eligibility._rule_based_ranking
// -----------------------------------------------------------------------------
function ruleBasedRanking(n_dim, _n_trials) {
    const BASELINE_TAIL = ["RandomSearch", "GridSearch"];
    if (n_dim <= 2) {
        return [
            "NelderMead", "PRIMA_UOBYQA", "PRIMA_NEWUOA", "Powell",
            "LBFGSB", "HillClimbing", "PatternSearch", "CoordinateDescent",
            ...BASELINE_TAIL,
        ];
    }
    if (n_dim <= 10) {
        return [
            "DifferentialEvolution", "CMAEvolutionStrategy", "ParticleSwarm",
            "PRIMA_BOBYQA", "BayesianOpt", "HarmonySearch", "GeneticAlgorithm",
            "PatternSearch", "EvolutionStrategy", ...BASELINE_TAIL,
        ];
    }
    if (n_dim <= 50) {
        return [
            "CMAEvolutionStrategy", "DifferentialEvolution", "EvolutionStrategy",
            "ParticleSwarm", "Rechenberg", "FireflyAlgorithm", "AntColonyOpt",
            "RandomSearch", "GeneticAlgorithm", "SimulatedAnnealing",
        ];
    }
    return [
        "Rechenberg", "RandomSearch", "ParticleSwarm", "DifferentialEvolution",
        "HillClimbing", "CoordinateDescent", "SimulatedAnnealing",
        "EvolutionStrategy", "GeneticAlgorithm",
    ];
}

// -----------------------------------------------------------------------------
// Grid lookup
// -----------------------------------------------------------------------------
function snapToGridCell(grid, n_dim, n_trials) {
    const cells = grid && grid.cells ? grid.cells : null;
    if (!cells) return null;
    const parsed = Object.keys(cells).map(k => {
        const [d, t] = k.split("/");
        return { key: k, d: parseInt(d, 10), t: parseInt(t, 10) };
    });

    // Prefer cells with d ≤ n_dim AND t ≤ n_trials (avoid recommending
    // from a higher-dim sweep where the easier algorithms got eliminated).
    let feasible = parsed.filter(c => c.d <= n_dim && c.t <= n_trials);
    if (feasible.length > 0) {
        feasible.sort((a, b) => {
            const da = Math.abs(a.d - n_dim), db = Math.abs(b.d - n_dim);
            if (da !== db) return da - db;
            return Math.abs(a.t - n_trials) - Math.abs(b.t - n_trials);
        });
    } else {
        // L1 distance fallback for callers below the smallest cell.
        feasible = parsed.slice();
        feasible.sort((a, b) => {
            const da = Math.abs(a.d - n_dim) + Math.abs(a.t - n_trials);
            const db = Math.abs(b.d - n_dim) + Math.abs(b.t - n_trials);
            return da - db;
        });
    }
    return cells[feasible[0].key] || null;
}

// -----------------------------------------------------------------------------
// recommend()
// -----------------------------------------------------------------------------
function recommend(n_dim, n_trials, eval_time = null, available = null, grid = undefined) {
    const universe = available || Object.keys(TIER);
    const candidates = new Set(eligible(universe, n_dim, n_trials, eval_time));
    const g = grid !== undefined ? grid : Grid;

    // Grid-driven pick.
    if (g) {
        const cell = snapToGridCell(g, n_dim, n_trials);
        if (cell) {
            const scored = [];
            for (const name of candidates) {
                const entry = cell[name];
                if (!entry) continue;
                let score = entry.borda_score;
                if (score === undefined || score === null
                    || score === Infinity || score === "Infinity") {
                    score = entry.median_best;
                }
                if (score === undefined || score === null
                    || score === Infinity || score === "Infinity") {
                    continue;
                }
                scored.push({ score, name });
            }
            if (scored.length > 0) {
                // Match Python's tuple-sort tie-break: when borda_score
                // is identical (which happens whenever two algorithms
                // had the same per-(objective, seed) ranks across the
                // suite), sort by algorithm name. Python's
                // `sorted([(score, name), ...])` does this implicitly
                // via tuple comparison; JS's numeric subtraction
                // returns 0 on ties and falls back to insertion order,
                // which would diverge from Python.
                scored.sort((a, b) => {
                    if (a.score !== b.score) return a.score - b.score;
                    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0;
                });
                return scored[0].name;
            }
        }
    }

    // Rule-based fallback.
    for (const name of ruleBasedRanking(n_dim, n_trials)) {
        if (candidates.has(name)) return name;
    }
    if (candidates.size > 0) return candidates.values().next().value;
    return "RandomSearch";
}

// -----------------------------------------------------------------------------
// Exports — same dual-mode pattern the other JS modules use.
// -----------------------------------------------------------------------------
const Eligibility = {
    TIER_TRIVIAL, TIER_LIGHT, TIER_MEDIUM, TIER_HEAVY, TIER_VERY_HEAVY,
    TIER, MIN_EVAL_TIME_FOR_TIER, DIM_CAP,
    minTrials, passesDim, passesTrials, passesEvalTime,
    filterByDim, filterByTrials, filterByEvalTime, eligible,
    timeObjective, recommend, snapToGridCell, ruleBasedRanking,
    get Grid() { return Grid; },
};

if (typeof module !== "undefined" && module.exports) {
    module.exports = Eligibility;
} else if (typeof globalThis !== "undefined") {
    globalThis.Eligibility = Eligibility;
}
